#!/usr/bin/env bash
#
# grant-user.sh — make the human a first-class agent spawner.
#
# Mints the human a user identity and an `agent/spawn` capability over
# `agent:fleet`, rooted at the monster-resident root, so the operator can spawn
# subagents directly (e.g. `moonshine agent spawn --node <bin>`) without going
# through Thoth. The token + secret are written under the edgework config dir
# (`~/.edgework/`) so the agent surface picks them up.
#
# Flow:
#   1. monster-resident keygen           -> {did, secret}  (the user's identity)
#   2. monster-resident grant            -> a UCAN granting agent/spawn on
#        --audience <did> --with agent:fleet --can agent/spawn
#   3. write token -> ~/.edgework/agent.ucan
#      write secret -> ~/.edgework/agent.key   (chmod 600)
#
# Idempotent-ish: warns and refuses to clobber existing files (pass nothing to
# re-run after removing them). No emojis. Does not build anything.

set -euo pipefail

# --- locate the monster-resident binary (release preferred, then debug) -------
script_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
resident_dir="$(cd "${script_dir}/../../monster-resident" && pwd)"

RESIDENT_BIN=""
for candidate in \
  "${resident_dir}/target/release/monster-resident" \
  "${resident_dir}/target/debug/monster-resident"; do
  if [[ -x "${candidate}" ]]; then
    RESIDENT_BIN="${candidate}"
    break
  fi
done

if [[ -z "${RESIDENT_BIN}" ]]; then
  echo "error: monster-resident binary not found." >&2
  echo "       looked under ${resident_dir}/target/{release,debug}/" >&2
  echo "       build it first: (cd ${resident_dir} && cargo build --release)" >&2
  exit 1
fi
echo "using monster-resident: ${RESIDENT_BIN}"

# --- edgework config dir + target paths ---------------------------------------
EDGEWORK_DIR="${HOME}/.edgework"
UCAN_PATH="${EDGEWORK_DIR}/agent.ucan"
KEY_PATH="${EDGEWORK_DIR}/agent.key"

mkdir -p "${EDGEWORK_DIR}"

# Refuse to clobber: this script provisions identity material; overwriting it
# would orphan any subagents already spawned under the old identity.
existing=0
for f in "${UCAN_PATH}" "${KEY_PATH}"; do
  if [[ -e "${f}" ]]; then
    echo "warning: ${f} already exists; refusing to overwrite." >&2
    existing=1
  fi
done
if [[ "${existing}" -ne 0 ]]; then
  echo "remove the existing files to re-provision, then re-run this script." >&2
  exit 1
fi

# --- 1. generate the user identity --------------------------------------------
echo "generating user identity..."
keygen_json="$("${RESIDENT_BIN}" keygen)"

# keygen prints {"did":"...","secret":"..."}; extract both fields.
USER_DID="$(printf '%s' "${keygen_json}" \
  | sed -n 's/.*"did"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p')"
USER_SECRET="$(printf '%s' "${keygen_json}" \
  | sed -n 's/.*"secret"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p')"

if [[ -z "${USER_DID}" || -z "${USER_SECRET}" ]]; then
  echo "error: could not parse did/secret from keygen output:" >&2
  echo "       ${keygen_json}" >&2
  exit 1
fi
echo "user did: ${USER_DID}"

# --- 2. mint the user capability ----------------------------------------------
echo "minting agent/spawn capability over agent:fleet..."
TOKEN="$("${RESIDENT_BIN}" grant \
  --audience "${USER_DID}" \
  --with agent:fleet \
  --can agent/spawn)"

if [[ -z "${TOKEN}" ]]; then
  echo "error: grant produced an empty token." >&2
  exit 1
fi

# --- 3. persist token + secret (secret 0600) ----------------------------------
# Write the secret with restrictive perms from the start.
( umask 077 && printf '%s\n' "${USER_SECRET}" > "${KEY_PATH}" )
chmod 600 "${KEY_PATH}"

printf '%s\n' "${TOKEN}" > "${UCAN_PATH}"

echo
echo "provisioned the human as a first-class agent spawner:"
echo "  identity (did) : ${USER_DID}"
echo "  capability     : agent/spawn on agent:fleet"
echo "  token          : ${UCAN_PATH}"
echo "  secret (0600)  : ${KEY_PATH}"
echo
echo "next:"
echo "  moonshine agent spawn --node <bin>"
